TableUtil = {}

function TableUtil.include(table, value)
    for _, var in pairs(table) do
        if var == value then
            return true
        end
    end
    return false
end

function TableUtil.copyTable(table)
    if not table then
        return table
    end
    local result = {}
    for key, value in pairs(table) do
        if type(value) == "table" then
            result[key] = TableUtil.copyTable(value)
        else
            result[key] = value
        end
    end
    return result
end

function TableUtil.appendArray(array1, array2)
    for _, value in pairs(array2) do
        table.insert(array1, value)
    end
end

function TableUtil.mergeTable(t1, t2, result)
    result = result or t1
    if result == t1 then
        for key, value in pairs(t2) do
            result[key] = value
        end
    else
        for key, value in pairs(t1) do
            result[key] = value
        end
        for key, value in pairs(t2) do
            result[key] = value
        end
    end
end

function TableUtil.mergeArray(t1, t2, result)
    result = result or t1
    if result == t1 then
        for _, value in pairs(t2) do
            table.insert(t1, value)
        end
    else
        for _, value in pairs(t1) do
            table.insert(result, value)
        end
        for _, value in pairs(t2) do
            table.insert(result, value)
        end
    end
end

function TableUtil.getTableByte(table)
    local byte = 0
    if not table then
        return byte
    end
    for key, value in pairs(table) do
        if type(value) == "table" then
            byte = byte + #tostring(key) + 5 + TableUtil.getTableByte(value)
        else
            byte = byte + #tostring(key) + 5 + #tostring(value)
        end
    end
    return byte
end

function TableUtil.getTableSize(table)
    if not table then
        return 0
    end
    local size = 0
    for _, _ in pairs(table) do
        size = size + 1
    end
    if size == #table then
        return size, "array"
    else
        return size, "map"
    end
end

function TableUtil.isArray(table)
    if not table then
        return false
    end
    if #table ~= 0 then
        return true
    end
    return TableUtil.isEmpty(table)
end

function TableUtil.isObject(table)
    if not table then
        return false
    end
    if #table ~= 0 then
        return false
    end
    return not TableUtil.isEmpty(table)
end

function TableUtil.isEmpty(table)
    return TableUtil.getTableSize(table) == 0
end

function TableUtil.isSameTable(t1, t2)
    if t1 == nil or t2 == nil then
        return false
    end
    if TableUtil.getTableSize(t1) ~= TableUtil.getTableSize(t2) then
        return false
    end
    for key, value in pairs(t2) do
        if type(value) == "table" then
            local same = TableUtil.isSameTable(value, t1[key])
            if not same then
                return false
            end
        else
            if value ~= t1[key] then
                return false
            end
        end
    end
    return true
end

function TableUtil.deleteEmptyValue(result)
    local len = #result
    for key, value in pairs(result) do
        if type(value) == "table" then
            TableUtil.deleteEmptyValue(value)
            if len > 0 and TableUtil.isEmpty(value) then
                table.remove(result, key)
                TableUtil.deleteEmptyValue(result)
                break
            end
        else
            if len > 0 and value == "" then
                table.remove(result, key)
                TableUtil.deleteEmptyValue(result)
                break
            elseif value == "" then
                result[key] = "0"
            end
        end
    end
end

function TableUtil.checkNotExistValue(t1, t2, result)
    for key, value in pairs(t1) do
        if t2[key] == nil then
            if not result then
                result = {}
            end
            if not result.__rm then
                result.__rm = {}
            end
            table.insert(result.__rm, key)
        else
            if type(value) == "table" then
                if not result then
                    result = {}
                end
                if TableUtil.isArray(value) and TableUtil.isObject(t2[key]) then
                    t1[key] = nil
                else
                    if not result[key] then
                        result[key] = {}
                    end
                    TableUtil.checkNotExistValue(value, t2[key], result[key])
                    if TableUtil.isEmpty(result[key]) then
                        result[key] = nil
                    end
                end
            end
        end
    end
end

function TableUtil.deleteSameValue(t1, t2, result, level)
    if t1 == nil or t2 == nil then
        return nil
    end
    level = (level or 99999) - 1
    result = result or {}
    for key, value in pairs(t2) do
        if type(value) == "table" then
            if level > 0 and TableUtil.isObject(value) then
                if t1[key] == nil then
                    result[key] = TableUtil.copyTable(value)
                    result[key].__add = true
                else
                    local child = TableUtil.deleteSameValue(t1[key], value, result[key], level)
                    if child and not TableUtil.isSameTable(t1[key], value) then
                        result[key] = child
                    end
                end
            else
                if not TableUtil.isSameTable(t1[key], value) then
                    result[key] = TableUtil.copyTable(value)
                end
            end
        else
            if value ~= t1[key] then
                result[key] = value
            end
        end
    end
    return result
end

function TableUtil.removeElementByFun(tbl, fun)
    local newTbl = {}
    for key, value in pairs(tbl) do
        if not fun(key, value) then
            newTbl[key] = value
        end
    end
    return newTbl
end

---删除tb表中的某个值
---@param tb table
---@param value any
function TableUtil.tableRemove(tb, value)
    if type(tb) ~= "table" then
        return
    end
    for key, v in pairs(tb) do
        if v == value then
            if type(key) == "number" then
                table.remove(tb, key)
            else
                tb[key] = nil
            end
            break
        end
    end
end

---判断tb表中是否包含值value
---@param tb table
---@param value any
function TableUtil.tableContain(tb, value)
    if type(tb) ~= "table" then
        return false
    end

    for _, v in pairs(tb) do
        if v == value then
            return true
        end
    end
    return false
end

